# Pytest Tests: Joint Account Holder Transactions & Ownership Modification

```python
"""
Test Suite: Joint Account Holder Transactions & Ownership Restrictions
Requirement: A joint-account holder shall perform transactions;
             the secondary holder shall not be able to modify ownership.
             Boundary behaviour at exact min/max thresholds must be tested.
"""

import pytest
from decimal import Decimal
from unittest.mock import MagicMock, patch
from dataclasses import dataclass, field
from typing import List, Optional
from enum import Enum, auto


# ---------------------------------------------------------------------------
# Domain model (production code assumed to live in src/banking/)
# Importing here; replace paths with your actual module structure
# ---------------------------------------------------------------------------
try:
    from src.banking.account import JointAccount, AccountHolder, HolderRole
    from src.banking.transaction import Transaction, TransactionType
    from src.banking.exceptions import (
        InsufficientFundsError,
        UnauthorisedOwnershipChangeError,
        TransactionLimitExceededError,
        BelowMinimumBalanceError,
        InvalidTransactionAmountError,
    )
except ImportError:
    # -----------------------------------------------------------------------
    # Inline stub implementation so the test file is self-contained and
    # runnable while the real production code is being developed.
    # Remove this block once production code exists.
    # -----------------------------------------------------------------------
    from decimal import Decimal
    from enum import Enum, auto
    from dataclasses import dataclass, field
    from typing import List, Optional

    class HolderRole(Enum):
        PRIMARY = auto()
        SECONDARY = auto()

    class TransactionType(Enum):
        DEPOSIT = auto()
        WITHDRAWAL = auto()
        TRANSFER = auto()

    class InsufficientFundsError(Exception):
        pass

    class UnauthorisedOwnershipChangeError(PermissionError):
        pass

    class TransactionLimitExceededError(Exception):
        pass

    class BelowMinimumBalanceError(Exception):
        pass

    class InvalidTransactionAmountError(ValueError):
        pass

    @dataclass
    class AccountHolder:
        holder_id: str
        name: str
        role: HolderRole

    @dataclass
    class Transaction:
        transaction_type: TransactionType
        amount: Decimal
        initiated_by: "AccountHolder"

    @dataclass
    class JointAccount:
        account_id: str
        primary_holder: AccountHolder
        secondary_holder: AccountHolder
        balance: Decimal = Decimal("0.00")
        minimum_balance: Decimal = Decimal("0.00")
        max_single_transaction: Decimal = Decimal("10000.00")
        max_daily_limit: Decimal = Decimal("20000.00")
        _daily_total: Decimal = field(default=Decimal("0.00"), init=False, repr=False)
        _transaction_history: List[Transaction] = field(
            default_factory=list, init=False, repr=False
        )

        # ---- helpers -------------------------------------------------------
        def _is_holder(self, holder: AccountHolder) -> bool:
            return holder.holder_id in (
                self.primary_holder.holder_id,
                self.secondary_holder.holder_id,
            )

        def _validate_holder(self, holder: AccountHolder) -> None:
            if not self._is_holder(holder):
                raise PermissionError(f"{holder.holder_id} is not a holder on this account.")

        def _validate_amount(self, amount: Decimal) -> None:
            if amount <= Decimal("0"):
                raise InvalidTransactionAmountError("Amount must be positive.")
            if amount > self.max_single_transaction:
                raise TransactionLimitExceededError(
                    f"Amount {amount} exceeds single-transaction limit {self.max_single_transaction}."
                )

        def _validate_daily_limit(self, amount: Decimal) -> None:
            if self._daily_total + amount > self.max_daily_limit:
                raise TransactionLimitExceededError(
                    f"Transaction would exceed daily limit {self.max_daily_limit}."
                )

        # ---- public transaction API ----------------------------------------
        def deposit(self, holder: AccountHolder, amount: Decimal) -> Transaction:
            self._validate_holder(holder)
            self._validate_amount(amount)
            self.balance += amount
            txn = Transaction(TransactionType.DEPOSIT, amount, holder)
            self._transaction_history.append(txn)
            return txn

        def withdraw(self, holder: AccountHolder, amount: Decimal) -> Transaction:
            self._validate_holder(holder)
            self._validate_amount(amount)
            self._validate_daily_limit(amount)
            if self.balance - amount < self.minimum_balance:
                raise InsufficientFundsError(
                    f"Withdrawal of {amount} would breach minimum balance {self.minimum_balance}."
                )
            self.balance -= amount
            self._daily_total += amount
            txn = Transaction(TransactionType.WITHDRAWAL, amount, holder)
            self._transaction_history.append(txn)
            return txn

        def transfer(
            self,
            holder: AccountHolder,
            amount: Decimal,
            target_account: "JointAccount",
        ) -> Transaction:
            self.withdraw(holder, amount)
            target_account.deposit(holder, amount)
            txn = Transaction(TransactionType.TRANSFER, amount, holder)
            return txn

        def get_transaction_history(self, holder: AccountHolder) -> List[Transaction]:
            self._validate_holder(holder)
            return list(self._transaction_history)

        # ---- ownership API -------------------------------------------------
        def add_holder(self, requesting_holder: AccountHolder, new_holder: AccountHolder) -> None:
            if requesting_holder.role != HolderRole.PRIMARY:
                raise UnauthorisedOwnershipChangeError(
                    "Only the primary holder may modify account ownership."
                )

        def remove_holder(self, requesting_holder: AccountHolder, target_holder: AccountHolder) -> None:
            if requesting_holder.role != HolderRole.PRIMARY:
                raise UnauthorisedOwnershipChangeError(
                    "Only the primary holder may modify account ownership."
                )

        def change_primary_holder(
            self, requesting_holder: AccountHolder, new_primary: AccountHolder
        ) -> None:
            if requesting_holder.role != HolderRole.PRIMARY:
                raise UnauthorisedOwnershipChangeError(
                    "Only the primary holder may transfer primary ownership."
                )

        def close_account(self, requesting_holder: AccountHolder) -> None:
            if requesting_holder.role != HolderRole.PRIMARY:
                raise UnauthorisedOwnershipChangeError(
                    "Only the primary holder may close the account."
                )

        def reset_daily_total(self) -> None:
            """Call at midnight / start of each banking day."""
            self._daily_total = Decimal("0.00")


# ===========================================================================
# Fixtures
# ===========================================================================

MIN_BALANCE = Decimal("0.00")
MAX_SINGLE_TXN = Decimal("10_000.00")
MAX_DAILY = Decimal("20_000.00")
INITIAL_BALANCE = Decimal("5_000.00")


@pytest.fixture
def primary_holder():
    return AccountHolder(holder_id="H001", name="Alice Primary", role=HolderRole.PRIMARY)


@pytest.fixture
def secondary_holder():
    return AccountHolder(holder_id="H002", name="Bob Secondary", role=HolderRole.SECONDARY)


@pytest.fixture
def unrelated_holder():
    return AccountHolder(holder_id="H999", name="Eve Outsider", role=HolderRole.SECONDARY)


@pytest.fixture
def joint_account(primary_holder, secondary_holder):
    return JointAccount(
        account_id="ACC-1234",
        primary_holder=primary_holder,
        secondary_holder=secondary_holder,
        balance=INITIAL_BALANCE,
        minimum_balance=MIN_BALANCE,
        max_single_transaction=MAX_SINGLE_TXN,
        max_daily_limit=MAX_DAILY,
    )


@pytest.fixture
def target_account(primary_holder, secondary_holder):
    """A separate joint account used as a transfer destination."""
    p = AccountHolder(holder_id="H003", name="Carol", role=HolderRole.PRIMARY)
    s = AccountHolder(holder_id="H004", name="Dave", role=HolderRole.SECONDARY)
    return JointAccount(
        account_id="ACC-5678",
        primary_holder=p,
        secondary_holder=s,
        balance=Decimal("0.00"),
        minimum_balance=MIN_BALANCE,
        max_single_transaction=MAX_SINGLE_TXN,
        max_daily_limit=MAX_DAILY,
    )


# ===========================================================================
# 1. Transaction authorisation – both holders may transact
# ===========================================================================

class TestTransactionAuthorisation:
    """Both primary and secondary holders are authorised to perform transactions."""

    # -- Deposits ------------------------------------------------------------

    def test_primary_holder_can_deposit(self, joint_account, primary_holder):
        txn = joint_account.deposit(primary_holder, Decimal("100.00"))
        assert txn.transaction_type == TransactionType.DEPOSIT
        assert joint_account.balance == INITIAL_BALANCE + Decimal("100.00")

    def test_secondary_holder_can_deposit(self, joint_account, secondary_holder):
        txn = joint_account.deposit(secondary_holder, Decimal("100.00"))
        assert txn.transaction_type == TransactionType.DEPOSIT
        assert joint_account.balance == INITIAL_BALANCE + Decimal("100.00")

    # -- Withdrawals ---------------------------------------------------------

    def test_primary_holder_can_withdraw(self, joint_account, primary_holder):
        txn = joint_account.withdraw(primary_holder, Decimal("200.00"))
        assert txn.transaction_type == TransactionType.WITHDRAWAL
        assert joint_account.balance == INITIAL_BALANCE - Decimal("200.00")

    def test_secondary_holder_can_withdraw(self, joint_account, secondary_holder):
        txn = joint_account.withdraw(secondary_holder, Decimal("200.00"))
        assert txn.transaction_type == TransactionType.WITHDRAWAL
        assert joint_account.balance == INITIAL_BALANCE - Decimal("200.00")

    # -- Transfers -----------------------------------------------------------

    def test_primary_holder_can_transfer(self, joint_account, primary_holder, target_account):
        joint_account.transfer(primary_holder, Decimal("500.00"), target_account)
        assert joint_account.balance == INITIAL_BALANCE - Decimal("500.00")
        assert target_account.balance == Decimal("500.00")

    def test_secondary_holder_can_transfer(self, joint_account, secondary_holder, target_account):
        joint_account.transfer(secondary_holder, Decimal("500.00"), target_account)
        assert joint_account.balance == INITIAL_BALANCE - Decimal("500.00")
        assert target_account.balance == Decimal("500.00")

    # -- Transaction history -------------------------------------------------

    def test_primary_holder_can_view_history(self, joint_account, primary_holder):
        joint_account.deposit(primary_holder, Decimal("100.00"))
        history = joint_account.get_transaction_history(primary_holder)
        assert len(history) == 1

    def test_secondary_holder_can_view_history(self, joint_account, secondary_holder, primary_holder):
        joint_account.deposit(primary_holder, Decimal("100.00"))
        history = joint_account.get_transaction_history(secondary_holder)
        assert len(history) == 1

    def test_unrelated_party_cannot_deposit(self, joint_account, unrelated_holder):
        with pytest.raises(PermissionError):
            joint_account.deposit(unrelated_holder, Decimal("100.00"))

    def test_unrelated_party_cannot_withdraw(self, joint_account, unrelated_holder):
        with pytest.raises(PermissionError):
            joint_account.withdraw(unrelated_holder, Decimal("100.00"))

    def test_transaction_records_initiating_holder(self, joint_account, secondary_holder):
        txn = joint_account.deposit(secondary_holder, Decimal("50.00"))
        assert txn.initiated_by.holder_id == secondary_holder.holder_id


# ===========================================================================
# 2. Ownership modification restrictions
# ===========================================================================

class TestOwnershipModificationRestrictions:
    """Secondary holder must NOT be able to modify account ownership in any way."""

    def test_secondary_cannot_add_holder(self, joint_account, secondary_holder):
        new_holder = AccountHolder("H005", "Frank", HolderRole.SECONDARY)
        with pytest.raises(UnauthorisedOwnershipChangeError):
            joint_account.add_holder(secondary_holder, new_holder)

    def test_secondary_cannot_remove_holder(self, joint_account, secondary_holder, primary_holder):
        with pytest.raises(UnauthorisedOwnershipChangeError):
            joint_account.remove_holder(secondary_holder, primary_holder)

    def test_secondary_cannot_change_primary_holder(
        self, joint_account, secondary_holder
    ):
        new_primary = AccountHolder("H006", "Grace", HolderRole.PRIMARY)
        with pytest.raises(UnauthorisedOwnershipChangeError):
            joint_account.change_primary_holder(secondary_holder, new_primary)

    def test_secondary_cannot_close_account(self, joint_account, secondary_holder):
        with pytest.raises(UnauthorisedOwnershipChangeError):
            joint_account.close_account(secondary_holder)

    def test_secondary_cannot_elevate_own_role(self, joint_account, secondary_holder):
        """Attempting self-promotion must fail."""
        with pytest.raises(UnauthorisedOwnershipChangeError):
            joint_account.change_primary_holder(secondary_holder, secondary_holder)

    # -- Primary holder IS allowed -------------------------------------------

    def test_primary_can_add_holder(self, joint_account, primary_holder):
        new_holder = AccountHolder("H007", "Heidi", HolderRole.SECONDARY)
        # Should NOT raise
        joint_account.add_holder(primary_holder, new_holder)

    def test_primary_can_remove_secondary(self, joint_account, primary_holder, secondary_holder):
        joint_account.remove_holder(primary_holder, secondary_holder)

    def test_primary_can_close_account(self, joint_account, primary_holder):
        joint_account.close_account(primary_holder)

    def test_primary_can_transfer_primary_role(self, joint_account, primary_holder):
        new_primary = AccountHolder("H008", "Ivan", HolderRole.PRIMARY)
        joint_account.change_primary_holder(primary_holder, new_primary)

    # -- Error message quality -----------------------------------------------

    def test_unauthorised_error_message_is_descriptive(
        self, joint_account, secondary_holder
    ):
        with pytest.raises(UnauthorisedOwnershipChangeError, match="primary"):
            joint_account.close_account(secondary_holder)


# ===========================================================================
# 3. Boundary behaviour – deposit amounts
# ===========================================================================

class TestDepositBoundaries:
    """Boundary tests around the minimum valid deposit amount and the
    single-transaction maximum."""

    @pytest.mark.parametrize(
        "amount, description",
        [
            (Decimal("0.00"), "exact zero"),
            (Decimal("-0.01"), "one cent below zero"),
            (Decimal("-1000.00"), "large negative"),
        ],
    )
    def test_deposit_invalid_amounts_rejected(
        self, joint_account, secondary_holder, amount, description
    ):
        with pytest.raises(InvalidTransactionAmountError, match="positive"), \
             pytest.raises(InvalidTransactionAmountError):
            joint_account.deposit(secondary_holder, amount)

    def test_deposit_minimum_valid_amount(self, joint_account, secondary_holder):
        """Smallest meaningful unit (1 cent / 0.01) is accepted."""
        txn = joint_account.deposit(secondary_holder, Decimal("0.01"))
        assert joint_account.balance == INITIAL_BALANCE + Decimal("0.01")

    def test_deposit_exactly_at_max_single_transaction(
        self, joint_account, secondary_holder
    ):
        txn = joint_account.deposit(secondary_holder, MAX_SINGLE_TXN)
        assert joint_account.balance == INITIAL_BALANCE + MAX_SINGLE_TXN

    def test_deposit_one_cent_above_max_single_transaction_rejected(
        self, joint_account, secondary_holder
    ):
        over_limit = MAX_SINGLE_TXN + Decimal("0.01")
        with pytest.raises(TransactionLimitExceededError):
            joint_account.deposit(secondary_holder, over_limit)

    def test_deposit_one_cent_below_max_single_transaction_accepted(
        self, joint_account, secondary_holder
    ):
        under_limit = MAX_SINGLE_TXN - Decimal("0.01")
        txn = joint_account.deposit(secondary_holder, under_limit)
        assert txn.amount == under_limit


# ===========================================================================
# 4. Boundary behaviour – withdrawal amounts
# ===========================================================================

class TestWithdrawalBoundaries:
    """Boundary tests around minimum balance, single-transaction limit,
    and daily limit."""

    # -- Minimum balance -----------------------------------------------------

    def test_withdraw_exactly_to_minimum_balance(self, joint_account, secondary_holder):
        """Withdrawing to exactly the minimum balance is permitted."""
        amount = joint_account.balance - joint_account.minimum_balance
        txn = joint_account.withdraw(secondary_holder, amount)
        assert joint_account.balance == joint_account.minimum_balance

    def test_withdraw_one_cent_below_minimum_balance_rejected(
        self, joint_account, secondary_holder
    ):
        """One cent over available-above-minimum must fail."""
        amount = joint_account.balance - joint_account.minimum_balance + Decimal("0.01")
        with pytest.raises(InsufficientFundsError):
            joint_account.withdraw(secondary_holder, amount)

    def test_withdraw_zero_rejected(self, joint_account, secondary_holder):
        with pytest.raises(InvalidTransactionAmountError):
            joint_account.withdraw(secondary_holder, Decimal("0.00"))

    def test_withdraw_negative_amount_rejected(self, joint_account, secondary_holder):
        with pytest.raises(InvalidTransactionAmountError):
            joint_account.withdraw(secondary_holder, Decimal("-1.00"))

    # -- Single-transaction limit -------------------------------------------

    def test_withdraw_exactly_at_max_single_transaction_limit(
        self, joint_account, secondary_holder
    ):
        """Seed sufficient balance first, then withdraw at the exact limit."""
        joint_account.balance = MAX_SINGLE_TXN + Decimal("1000.00")
        txn = joint_account.withdraw(secondary_holder, MAX_SINGLE_TXN)
        assert txn.amount == MAX_SINGLE_TXN

    def test_withdraw_one_cent_above_max_single_transaction_rejected(
        self, joint_account, secondary_holder
    ):
        joint_account.balance = MAX_SINGLE_TXN + Decimal("1000.00")
        with pytest.raises(TransactionLimitExceededError):
            joint_account.withdraw(secondary_holder, MAX_SINGLE_TXN + Decimal("0.01"))

    def test_withdraw_one_cent_below_max_single_transaction_accepted(
        self, joint_account, secondary_holder
    ):
        amount = MAX_SINGLE_TXN - Decimal("0.01")
        joint_account.balance = amount + Decimal("1.00")
        txn = joint_account.withdraw(secondary_holder, amount)
        assert txn.amount == amount

    # -- Daily limit ---------------------------------------------------------

    def test_cumulative_withdrawals_exactly_at_daily_limit_accepted(
        self, joint_account, secondary_holder
    ):
        """Two equal withdrawals that together exactly reach the daily limit."""
        joint_account.balance = MAX_DAILY + Decimal("100.00")
        half = MAX_DAILY / 2
        joint_account.withdraw(secondary_holder, half)
        joint_account.withdraw(secondary_holder, half)
        assert joint_account._daily_total == MAX_DAILY

    def test_withdrawal_exceeding_daily_limit_rejected(
        self, joint_account, secondary_holder
    ):
        joint_account.balance = MAX_DAILY + Decimal("100.00")
        half = MAX_DAILY / 2
        joint_account.withdraw(secondary_holder, half)
        joint_account.withdraw(secondary_holder, half)
        with pytest.raises(TransactionLimitExceededError):
            joint_account.withdraw(secondary_holder, Decimal("0.01"))

    def test_daily_total_resets_correctly(self, joint_account, secondary_holder):
        joint_account.balance = MAX_DAILY + Decimal("100.00")
        joint_account.withdraw(secondary_holder, MAX_DAILY / 2)
        joint_account.reset_daily_total()
        # Should now succeed without raising
        joint_account.withdraw(secondary_holder, MAX_DAILY / 2)
        assert joint_account._daily_total == MAX_DAILY / 2


# ===========================================================================
# 5. Boundary behaviour – account balance edge cases
# ===========================================================================

class TestBalanceBoundaries:
    """Edge cases where the balance itself is at boundary values."""

    def test_account_with_zero_balance_cannot_be_withdrawn_from(
        self, primary_holder, secondary_holder
    ):
        zero_balance_account = JointAccount(
            account_id="ACC-ZERO",
            primary_holder=primary_holder,
            secondary_holder=secondary_holder,
            balance=Decimal("0.00"),
            minimum_balance=Decimal("0.00"),
            max_single_transaction=MAX_SINGLE_TXN,
            max_daily_limit=MAX_DAILY,
        )
        with pytest.raises((InsufficientFundsError, InvalidTransactionAmountError)):
            zero_balance_account.withdraw(secondary_holder, Decimal("0.01"))

    def test_deposit_increases_balance_exactly(self, joint_account, secondary_holder):
        deposit_amount = Decimal("1234.56")
        expected = joint_account.balance + deposit_amount
        joint_account.deposit(secondary_holder, deposit_amount)
        assert joint_account.balance == expected

    def test_withdrawal_decreases_balance_exactly(self, joint_account, primary_holder):
        withdraw_amount = Decimal("999.99")
        expected = joint_account.balance - withdraw_amount
        joint_account.withdraw(primary_holder, withdraw_amount)
        assert joint_account.balance == expected

    def test_account_with_non_zero_minimum_balance_enforced(
        self, primary_holder, secondary_holder
    ):
        """Account with a £500 minimum balance should refuse withdrawal that would breach it."""
        min_bal = Decimal("500.00")
        account = JointAccount(
            account_id="ACC-MIN",
            primary_holder=primary_holder,
            secondary_holder=secondary_holder,
            balance=Decimal("600.00"),
            minimum_balance=min_bal,
            max_single_transaction=MAX_SINGLE_TXN,
            max_daily_limit=MAX_DAILY,
        )
        with pytest.raises(InsufficientFundsError):
            account.withdraw(secondary_holder, Decimal("101.00"))

    def test_account_with_non_zero_minimum_balance_allows_exact_withdrawal(
        self, primary_holder, secondary_holder
    ):
        min_bal = Decimal("500.00")
        account = JointAccount(
            account_id="ACC-MIN2",
            primary_holder=primary_holder,
            secondary_holder=secondary_holder,
            balance=Decimal("600.00"),
            minimum_balance=min_bal,
            max_single_transaction=MAX_SINGLE_TXN,
            max_daily_limit=MAX_DAILY,
        )
        # Exactly 100 available above the minimum
        txn = account.withdraw(secondary_holder, Decimal("100.00"))
        assert account.balance == min_bal


# ===========================================================================
# 6. Transaction integrity & audit
# ===========================================================================

class TestTransactionIntegrity:
    """Ensure every transaction is persisted and attributable."""

    def test_every_deposit_is_recorded_in_history(
        self, joint_account, primary_holder, secondary_holder
    ):
        joint_account.deposit(primary_holder, Decimal("100.00"))
        joint_account.deposit(secondary_holder, Decimal("200.00"))
        history = joint_account.get_transaction_history(primary_holder)
        assert len(history) == 2

    def test_every_withdrawal_is_recorded_in_history(
        self, joint_account, primary_holder, secondary_holder
    ):
        joint_account.withdraw(primary_holder, Decimal("100.00"))
        joint_account.withdraw(secondary_holder, Decimal("200.00"))
        history = joint_account.get_transaction_history(primary_holder)
        assert len(history) == 2

    def test_failed_transaction_is_not_recorded(
        self, joint_account, secondary_holder
    ):
        with pytest.raises(TransactionLimitExceededError):
            joint_account.deposit(secondary_holder, MAX_SINGLE_TXN + Decimal("1.00"))
        history = joint_account.get_transaction_history(secondary_holder)
        assert len(history) == 0

    def test_failed_withdrawal_does_not_alter_balance(
        self, joint_account, secondary_holder
    ):
        original_balance = joint_account.balance
        with pytest.raises(InsufficientFundsError):
            joint_account.withdraw(
                secondary_holder, joint_account.balance + Decimal("1.00")
            )
        assert joint_account.balance == original_balance

    def test_transaction_amounts_stored_with_full_precision(
        self, joint_account, secondary_holder
    ):
        amount = Decimal("1234.56")
        txn = joint_account.deposit(secondary_holder, amount)
        assert txn.amount == amount

    @pytest.mark.parametrize("num_transactions", [1, 10, 50])
    def test_history_length_matches_transaction_count(
        self, joint_account, primary_holder, num_transactions
    ):
        for i in range(num_transactions):
            joint_account.deposit(primary_holder, Decimal("1.00"))
        history = joint_account.get_transaction_history(primary_holder)
        assert len(history) == num_transactions


# ===========================================================================
# 7. Parametrised cross-role transaction coverage
# ===========================================================================

class TestCrossRoleTransactions:
    """Parametrised to ensure both roles pass the same transaction scenarios."""

    @pytest.mark.parametrize("holder_fixture", ["primary_holder", "secondary_holder"])
    def test_any_holder_can_make_standard_deposit(
        self, request, joint_account, holder_fixture
    ):
        holder = request.getfixturevalue(holder_fixture)
        txn = joint_account.deposit(holder, Decimal("50.00"))
        assert txn.transaction_type == TransactionType.DEPOSIT

    @pytest.mark.parametrize("holder_fixture", ["primary_holder", "secondary_holder"])
    def test_any_holder_can_make_standard_withdrawal(
        self, request, joint_account, holder_fixture
    ):
        holder = request.getfixturevalue(holder_fixture)
        txn = joint_account.withdraw(holder, Decimal("50.00"))
        assert txn.transaction_type == TransactionType.WITHDRAWAL

    @pytest.mark.parametrize("holder_fixture", ["primary_holder", "secondary_holder"])
    def test_any_holder_is_rejected_for_over_limit_deposit(
        self, request, joint_account, holder_fixture
    ):
        holder = request.getfixturevalue(holder_fixture)
        with pytest.raises(TransactionLimitExceededError):
            joint_account.deposit(holder, MAX_SINGLE_TXN + Decimal("0.01"))

    @pytest.mark.parametrize("holder_fixture", ["primary_holder", "secondary_holder"])
    def test_any_holder_is_rejected_for_overdraft(
        self, request, joint_account, holder_fixture
    ):
        holder = request.getfixturevalue(holder_fixture)
        with pytest.raises(InsufficientFundsError):
            joint_account.withdraw(holder, joint_account.balance + Decimal("0.01"))

    @pytest.mark.parametrize("holder_fixture", ["primary_holder", "secondary_holder"])
    def test_ownership_change_always_raises_for_secondary(
        self, request, joint_account, holder_fixture
    ):
        """Primary succeeds; secondary always raises. Parametrised for contrast."""
        holder = request.getfixturevalue(holder_fixture)
        new_holder = AccountHolder("H010", "Judy", HolderRole.SECONDARY)
        if holder.role == HolderRole.SECONDARY:
            with pytest.raises(UnauthorisedOwnershipChangeError):
                joint_account.add_holder(holder, new_holder)
        else:
            # Primary – must not raise
            joint_account.add_holder(holder, new_holder)
